ValidationRule.errorConditionFormula:
AND(
    ISCHANGED(Application_Status__c),

    /* Block normal users (allow system automation) */
    NOT(
        OR(
            TEXT($User.UserType) = "AutomatedProcess",
            TEXT($User.UserType) = "Integration"
        )
    ),

    /* Allow specific manual statuses */
    NOT(
        OR(
            ISPICKVAL(Application_Status__c, "Draft"),
            ISPICKVAL(Application_Status__c, "Submitted"),
            ISPICKVAL(Application_Status__c, "Withdrawn")
        )
    )
)
